(function(){
'use strict';
if(!window.amsSyncBeacon)return;
var c=amsSyncBeacon,t='';
try{var m=document.cookie.match(/(?:^|; )ams_subscriber_token=([^;]*)/);if(m)t=decodeURIComponent(m[1]);}catch(e){}
var d=new FormData();
d.append('action','ams_sync_product_view');
d.append('product_id',c.productId);
d.append('subscriber_token',t);
d.append('nonce',c.nonce);
if(navigator.sendBeacon){navigator.sendBeacon(c.ajaxUrl,d);}
else{var x=new XMLHttpRequest();x.open('POST',c.ajaxUrl);x.send(d);}
})();
